const body = $input.item.json.body || $input.item.json;
const out = [];

if (!body.entry) return [];

for (const e of body.entry) {
  const phoneNumberId = e.changes?.[0]?.value?.metadata?.phone_number_id;
  for (const change of e.changes || []) {
    const messages = change.value?.messages || [];
    const contacts = change.value?.contacts || [];
    for (const msg of messages) {
      let text = '';
      if (msg.type === 'text') text = msg.text?.body || '';
      else if (msg.type === 'button') text = msg.button?.text || '';
      else if (msg.type === 'interactive') {
        text = msg.interactive?.button_reply?.title
            || msg.interactive?.list_reply?.title
            || msg.interactive?.button_reply?.description
            || '';
      }
      else if (msg.type === 'image') text = '[User sent an image]';
      else if (msg.type === 'audio' || msg.type === 'voice') text = '[User sent a voice note]';
      else if (msg.type === 'document') text = '[User sent a document]';
      else if (msg.type === 'location') text = `[User shared location: ${msg.location?.latitude},${msg.location?.longitude}]`;
      else text = `[Unsupported message type: ${msg.type}]`;

      out.push({
        json: {
          from: msg.from,
          message_id: msg.id,
          message_type: msg.type,
          text,
          profile_name: contacts.find(c => c.wa_id === msg.from)?.profile?.name || 'Customer',
          phone_number_id: phoneNumberId,
          timestamp: msg.timestamp,
          session_id: msg.from
        }
      });
    }
  }
}
return out;
